import{_ as i,o as n,c as r,ag as t}from"./chunks/framework.DXGyWiRo.js";const l="/images/uebung037.jpg",s="/images/uebung038.jpg",c=JSON.parse('{"title":"Übung Lektion 24","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung24.md","filePath":"lektionen/uebung24.md"}'),a={name:"lektionen/uebung24.md"};function p(u,e,h,o,d,m){return n(),r("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-24" tabindex="-1">Übung Lektion 24 <a class="header-anchor" href="#ubung-lektion-24" aria-label="Permalink to &quot;Übung Lektion 24&quot;">​</a></h1><p>A) Bilden Sie den Dativ Singular und den Dativ/(Ablativ) Plural und geben Sie die Bedeutung des Nominalstamms an:</p><ol><li>श्रव Hören श्रवणाय । श्रवणेभ्यस्</li><li>भवन Werden भवाय । भवनेभ्यस्</li><li>गति Weg, Ziel गतये । गत्यै । गतिभ्यस्</li><li>ऋषि vedischer Weiser ऋषये । ऋषिभ्यस्</li><li>सुख Glück सुखाय । सुखेभ्यस्</li><li>गमन Gehen गमनाय । गमनेभ्यस्</li><li>जय Sieg जयाय । जयेभ्यस्</li><li>साधु gut साधवे । साधुभ्यस् । साध्व्यै । साध्वीभ्यस्</li><li>धेनु Milchkuh धेनवे । धेन्वै । धेनुभ्यस्</li><li>शुद्रा Śūdrafrau शूद्रायै । शूद्राभ्यस्</li><li>ब्राह्मणी Brahmanin ब्राह्मण्यै । ब्राह्मणीभ्यस्</li><li>अग्नि Feuer अग्नये । अग्निभ्यस्</li><li>एतद् ३ dieses एतस्मै । एतेभ्यस् । एतस्यै । एताभ्यस्</li><li>सन्त् seiend, wahr, gut सते । सद्भ्यस् । सत्यै । सतीभ्यस्</li><li>बुद्धिमन्त् einsichtig बुद्धिमते । बुद्धिमद्भ्यस् । बुद्धिमत्यै । बुद्धिमतीभ्यस्</li><li>यज्ञ Opfer यज्ञाय । यज्ञेभ्यस्</li><li>वचन sprechend, Sprechen वचनाय । वचनेभ्यस्</li><li>सत्यवन्त् wahrhaftig सत्यवते । सर्]त्यवद्भ्यस्</li><li>स्मृति Vergegenwärtigung, Erinnerung, Überlieferung, Tradition स्मृतये । स्मृत्यै । स्मृतिभ्यस्</li><li>सर्ग Schöpfung सर्गाय । सर्गेभ्यस्</li><li>स्वर्ग Himmel स्वर्गाय । स्वर्गेभ्यस्</li><li>दर्शन Sehen दर्शनाय । दर्शनेभ्यस्</li><li>सृष्टि Schöpfung सृष्टये । सृष्ट्यै । सृष्टिभ्यस्</li><li>अर्हन्त् würdig, vollkommen Erlöster अर्हते । अर्हद्भ्यस्</li><li>भक्ति Hingabe, Liebe भक्तये । भक्त्यै । भक्तिभ्यस्</li><li>दोष Fehler दोषाय । दोषेभ्यस्</li><li>पूजा Verehrung पूजायै । पूजाभ्यस्</li><li>दासी Leibeigene, Dienerin दास्यै । दासीभ्यस्</li><li>गुरु schwer, Meister, Lehrer गुरवे । गुरुभ्यस् । गुर्व्यै । गुर्वीभ्यस्</li></ol><p>B) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>ब्राह्मणो देवप्रतिमादर्शनाय गर्भगृहं विशति ॥१॥ देवस्य प्रतिमाया दर्शनाय । गर्भमेवे गृहम् । Der Brahmane betritt das innere Heiligtum, um das Götterbildnis zu sehen.</p><p>नरा धनलाभाय व्रतानि चरन्ति ॥२॥ धनस्य लाभाय । Menschen halten Gelübde, um reich zu werden.</p><p>गुरुर्धर्मोपदेशाय नगरं गतः ॥३॥ धर्मस्योपदेशाय । Der Meister ist in die Stadt gegangen, um Dharma zu unterrichten.</p><p>बाला अपि गुरुवचनश्रुत्यै नगरं गताः ॥४॥ गुरोर्वचनस्य श्रुत्यै । Auch die Kinder sind in die Stadt gegangen, um die Rede des Meisters zu hören.</p><p>देवप्रतिमायै गृहं गर्भगृहम् ॥५॥ देवस्य प्रतिमायै । गर्भ एव गृहम् । Das Innere Heiligtum ist ein Gebäude fürs Götterbild.</p><p>स्वर्गेभ्यो नराः पुण्यं कर्तुमिच्छन्ति ॥६॥ Menschen wollen um der Himmel willen Verdienstvolles tun.</p><p>मोक्षार्थं बुद्धगता बुद्ध्याप्तिमिच्छन्ति ॥७॥ मोक्षस्यार्थम् । बुद्धं गताः । बुद्धेराप्तिम् । Um erlöst zu werden, wollen Einsichtige erlösende Einsicht erlangen</p><p>देवास्तेभ्यो ऽकृतपुजाब्रामणेभ्यः क्रुध्यन्ति ॥८॥ न कृता पूजा यैस्तेभ्यो ब्राह्मणेभ्यः । Die Götter zürnen diesen Brahmanen, die ihnen keine Verehrung zollten.</p><p>मरणाय जना जायन्ते ॥९॥ Um zu sterben, werden Lebewesen geboren.</p><p>C) Geben Sie die Sätze B) 1-4 in Sanskrit wieder, indem Sie statt der Dative Infinitive (तुमुन्) setzen. Beachten Sie, dass der Infinitiv den gleichen Kasus regiert wie das entsprechende Verb.</p><p>ब्राह्मणो देवप्रतिमादर्शनाय गर्भगृहं विशति ॥१॥ ब्राह्मणो देवप्रतिमां द्रष्टुं गर्भगृहं विशति ॥१॥</p><p>नरा धनलाभाय व्रतानि चरन्ति ॥२॥ नरा धनं लब्धुं व्रतानि चरन्ति ॥२॥</p><p>गुरुर्धर्मोपदेशाय नगरं गतः ॥३॥ गुरुर्धर्ममुपदेष्टुं नगरं गतः ॥३॥</p><p>बाला अपि गुरुवचनश्रुत्यै नगरं गताः ॥४॥ बाला अपि गुरुवचनं श्रोतुं नगरं गताः ॥४॥</p><p>D) Ersetzen Sie in Satz A) 7 die Konstruktion mit -अर्थ durch einen gleichwertigen Dativ.</p><p>मोक्षार्थं बुद्धगता बुद्ध्याप्तिमिच्छन्ति ॥७॥ मोक्षाय बुद्धगता बुद्ध्याप्तिमिच्छन्ति ॥७॥</p><p>E) Ersetzen Sie in Satz A) 6 die Dativkonstruktion durch eine gleichwertige Konstruktion mit -अर्थ</p><p>स्वर्गेभ्यो नराः पुण्यं कर्तुमिच्छन्ति ॥६॥ स्वर्गार्थेन । स्वर्गार्थं। स्वर्गार्थाय नराः पुण्यं कर्तुमिच्छन्ति ॥६॥</p><p><img src="'+l+'" alt=""><br> Abb.: मरणाय जना जायन्ते<br> Nepal = नेपाल<br> [Bildquelle: ~Ans~. -- <a href="http://www.flickr.com/photos/ansdeblauwe/467399654/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ansdeblauwe/467399654/</a>. -- Zugriff am 2008-12-24. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>Übersetzen Sie ins Sanskrit:</p><p>1. Die Göttin, der man nicht geopfert hat, zürnt den Menschen. अनिष्टदेवी नरेभ्यः क्रुध्यति । कुप्यति ॥१॥</p><p>2. Er lässt die Kuh ins Dorf los. ग्रामाय धेनुं मुञ्जति ॥२॥</p><p>3. Jetzt reichts = Genug mit der Geduld. Aber: अलं क्षमया ॥३॥</p><p>4. Das ist gut (हित, सुख) für einen Brahmanen. एतद्ब्राह्मणाय सुखम् । हितम् ॥४॥</p><p>5. Verehrung (नमस्)  sei Śiva! Verehrung sei Śrī Gaṇeśa! शिवाय नमः । श्रीगणेशाय नमः ॥५॥</p><p>6. Auf Wiedersehen! = Wohlergehen (स्वस्ति f.)  Ihnen! स्वस्ति भवते । भवद्भ्यः । भवत्यै । भवतीभ्यः ॥६॥</p><p>7. Diese Frucht reicht zum Essen. इदं फलं अलं खादनाय ॥७॥</p><p>8. Ein Kämpfer ist dem (anderen) Kämpfer gewachsen (शक्त). शक्तो योधो योधाय ॥८॥</p><p>9. Selbst Viṣṇu übertrifft (प्र-भू + Dat.) Śiva nicht. विष्णुरपि शिवाय न प्रभवति ॥९॥</p><p>10. Nachdem ich mich vor den drei Weisen (Akk.) verbeugt habe (नमस्कृ)... Er verbeugt sich vor Narasiṃha (Dat.) मुनित्रयम् नमस्कृत्य ... । नरसिंहाय नमस्करोति ॥१०॥</p><p>11. Willkommen (स्वागतम्)  Ihnen. Willkommen der Königin. स्वागतं भवद्भ्यः । स्वागतं देव्यै ॥११॥</p><p>12. Ich wünsche Ihnen Wohlergehen (कुशल) = Wohlergehen Ihnen! भवद्भ्यः कुशलम् ॥१२॥</p><p>13. Er betrachtet ihn nicht als Grashalm. न तं तृणाय (तृणं) मन्यते ॥१३॥</p><p>14. Es reicht eine Frucht zum Essen und Wasser zum Trinken. अलं फलं खादनाय पानाय जलम् ॥१४॥</p><p>15. Auf Widersehen! (Neusanskrit: पुनर्दर्शनाय) पुनर्दर्शनाय ॥१५॥</p><p><img src="'+s+'" alt=""><br> Abb.: इदं फलं अलं खादनाय<br> Jackfruit = <em>Artocarpus heterophyllus</em> Lam.<br> [Bildquelle: mattlogelin. -- <a href="http://www.flickr.com/photos/mattlogelin/834840160/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mattlogelin/834840160/</a>. -- Zugriff am 2008-12-24. --  <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p>',41)])])}const b=i(a,[["render",p]]);export{c as __pageData,b as default};
